class User(props: Map<String, Any?>) {
    val name: String by props        // map-backed property
    val age: Int by props
}

fun table(init: Table.() -> Unit): Table = Table().apply(init)

class Table {
    private val rows = mutableListOf<Row>()
    fun row(init: Row.() -> Unit) { rows += Row().apply(init) }
}

val report = table {
    row { cell("Name"); cell("Score") }
    row { cell("Riadh"); cell("1450") }
}

@DslMarker
annotation class ReportDsl

@ReportDsl class Table { ... }
@ReportDsl class Row { ... }
// now row { row { } } is a compile error; this@table.row() still allowed

fun validate(user: User?) {
    contract { returns() implies (user != null) }
    requireNotNull(user) { "user required" }
}

validate(input)
input.email   // smart-cast: non-null after validate()

